  'con.sub.room':      { en: 'Room Reservation',       fr: 'Réservation de chambre' },
  'con.sub.rest':      { en: 'Restaurant Reservation', fr: 'Réservation restaurant' },
  'con.sub.spa':       { en: 'Spa Booking',            fr: 'Réservation spa' },
  'con.sub.event':     { en: 'Event / Wedding',        fr: 'Événement / Mariage' },
  'con.sub.group':     { en: 'Group Booking',          fr: 'Réservation de groupe' },
  'con.sub.other':     { en: 'Other',                  fr: 'Autre' },
  'con.book.eyebrow':  { en: 'Online Booking',         fr: 'Réservation en ligne' },
  'con.book.h2':       { en: 'Reserve Your Room at LeMar', fr: 'Réservez votre chambre à LeMar' },
  'con.book.p':        { en: 'Complete the form and our reservations team will confirm your booking within 24 hours with a personalised confirmation and pre-arrival guide.',
                         fr: 'Remplissez le formulaire et notre équipe confirmera votre réservation sous 24 heures avec une confirmation personnalisée et un guide pré-arrivée.' },
  'con.book.h1':       { en: 'Best rate guarantee on direct bookings', fr: 'Meilleur tarif garanti sur les réservations directes' },
