  /* ─── SPA PAGE: eyebrows, stats, treatment keys ─── */
  'spa.eyebrow':        { en: 'Wellness & Renewal',      fr: 'Bien-être & Renouveau' },
  'spa.h1':             { en: 'Élan Spa & Wellness',     fr: 'Spa Élan & Bien-être' },
  'spa.phil.ey':        { en: 'Our Philosophy',          fr: 'Notre philosophie' },
  'spa.stat.rooms':     { en: 'Treatment Rooms',         fr: 'Salles de soins' },
  'spa.stat.rituals':   { en: 'Signature Rituals',       fr: 'Rituels signatures' },
  'spa.stat.natural':   { en: 'Natural Products',        fr: 'Produits naturels' },
  'spa.rituals.ey':     { en: 'Signature Collections',   fr: 'Collections signatures' },
  'spa.treat.ey':       { en: 'Treatments Menu',         fr: 'Menu des soins' },
  'spa.treat.h2':       { en: 'Choose Your Experience',  fr: 'Choisissez votre expérience' },
  'spa.t1.h3':          { en: 'African Deep Tissue Massage', fr: 'Massage profond africain' },
  'spa.t1.p':           { en: 'A therapeutic full-body massage using warm shea butter and deep-pressure techniques rooted in West African healing traditions. Releases chronic tension and restores muscular balance.',
                          fr: 'Un massage thérapeutique corps entier au beurre de karité chaud et aux techniques de pression profonde ancrées dans les traditions de guérison d\'Afrique de l\'Ouest. Libère les tensions chroniques et restaure l\'équilibre musculaire.' },
  'spa.t1.meta1':       { en: '60 / 90 min',             fr: '60 / 90 min' },
  'spa.meta.indiv':     { en: 'Individual',              fr: 'Individuel' },
  'spa.meta.couples':   { en: 'Couples',                 fr: 'Couples' },
  'spa.meta.group':     { en: 'Group (up to 4)',         fr: 'Groupe (jusqu\'à 4)' },
  'spa.t2.h3':          { en: 'Baobab Oil Wrap',         fr: 'Enveloppement à l\'huile de baobab' },
  'spa.t2.p':           { en: 'A nourishing full-body wrap using cold-pressed baobab oil, rich in vitamins A, D, E and F. Deeply moisturises and rejuvenates skin, leaving it radiant and supple.',
                          fr: 'Un enveloppement corps nourrissant à l\'huile de baobab pressée à froid, riche en vitamines A, D, E et F. Hydrate et rajeunit profondément la peau, la laissant radieuse et souple.' },
  'spa.t3.h3':          { en: 'Volcanic Stone Therapy',  fr: 'Thérapie aux pierres volcaniques' },
  'spa.t3.p':           { en: 'Heated basalt stones are placed along the body\'s energy meridians to dissolve deep muscle tension, improve circulation, and induce profound relaxation.',
                          fr: 'Des pierres de basalte chauffées sont disposées le long des méridiens énergétiques du corps pour dissoudre les tensions musculaires profondes, améliorer la circulation et induire une relaxation profonde.' },
  'spa.t4.h3':          { en: 'Couples Ritual',          fr: 'Rituel Couples' },
  'spa.t4.p':           { en: 'A shared journey for two — beginning with a side-by-side foot bath, followed by simultaneous full-body massages, and concluding with a private bath infused with frangipani and rose petals.',
                          fr: 'Un voyage partagé pour deux — débutant par un bain de pieds côte à côte, suivi de massages corps entier simultanés, et se concluant par un bain privé infusé de frangipanier et de pétales de rose.' },
  'spa.t5.h3':          { en: 'Facial & Glow Treatment', fr: 'Soin visage & Éclat' },
  'spa.t5.p':           { en: 'A results-driven facial using local moringa and marula oil. Deep cleanse, exfoliation, mask and bespoke serum application for skin that glows with health.',
                          fr: 'Un soin visage axé sur les résultats avec de l\'huile locale de moringa et de marula. Nettoyage profond, exfoliation, masque et application de sérum sur mesure pour une peau qui rayonne de santé.' },
  'spa.t6.h3':          { en: 'Wellness Journey (Group)', fr: 'Parcours bien-être (Groupe)' },
  'spa.t6.p':           { en: 'Designed for groups of up to four, this guided wellness session includes a shared ritual bath, group meditation, and individual relaxation massages — ideal for retreats or celebrations.',
                          fr: 'Conçu pour des groupes allant jusqu\'à quatre personnes, cette session de bien-être guidée comprend un bain rituel partagé, une méditation de groupe et des massages de relaxation individuels — idéal pour des retraites ou des célébrations.' },
  'spa.gallery.ey':     { en: 'The Space',               fr: 'L\'espace' },
  'spa.resv.h4':        { en: 'Reservations',            fr: 'Réservations' },
  'spa.resv.p':         { en: 'We recommend booking 24 hours in advance. Hotel guests have priority access. Walk-ins welcome subject to availability.',
                          fr: 'Nous recommandons de réserver 24 heures à l\'avance. Les hôtes de l\'hôtel bénéficient d\'un accès prioritaire. Les visites sans rendez-vous sont bienvenues sous réserve de disponibilité.' },
