/* ============================================================
   LANGUAGE ENGINE
   ============================================================ */
const LeMar_i18n = (function () {
  const STORAGE_KEY = 'lemar_lang';
  const SUPPORTED   = ['en', 'fr'];

  // Detect preferred language
  function detectLang() {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored && SUPPORTED.includes(stored)) return stored;
    // Browser language
    const browserLang = (navigator.language || navigator.userLanguage || 'en').slice(0, 2).toLowerCase();
    return SUPPORTED.includes(browserLang) ? browserLang : 'en';
  }

  let currentLang = detectLang();

  // Apply a specific key to a node
  function applyKey(el, key, lang) {
    const dict = LEMAR_TRANSLATIONS[key];
    if (!dict) return;
    const val = dict[lang] || dict['en'];
    if (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') {
      el.placeholder = val;
    } else if (el.tagName === 'OPTION') {
      el.textContent = val;
    } else if (val.includes('<br>')) {
      el.innerHTML = val;
    } else {
      el.innerHTML = val;
    }
  }

  // Update all tagged elements in the document
  function applyAll(lang) {
    document.querySelectorAll('[data-i18n]').forEach(el => {
      applyKey(el, el.dataset.i18n, lang);
    });
    // Handle placeholder-specific elements
    document.querySelectorAll('[data-i18n-ph]').forEach(el => {
      const dict = LEMAR_TRANSLATIONS[el.dataset.i18nPh];
      if (dict) el.placeholder = dict[lang] || dict['en'];
    });
    // Update lang attribute
    document.documentElement.lang = lang;
    // Update switcher buttons
    document.querySelectorAll('.lang-btn').forEach(btn => {
      btn.classList.toggle('active', btn.dataset.lang === lang);
    });
  }

  function setLang(lang) {
    if (!SUPPORTED.includes(lang)) return;
    currentLang = lang;
    localStorage.setItem(STORAGE_KEY, lang);
    applyAll(lang);
  }

  function init() {
    applyAll(currentLang);
    // Wire up switcher buttons
    document.querySelectorAll('.lang-btn').forEach(btn => {
      btn.addEventListener('click', () => setLang(btn.dataset.lang));
    });
  }

  return { init, setLang, get lang() { return currentLang; } };
})();

// Auto-init when DOM is ready
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', LeMar_i18n.init);
} else {
  LeMar_i18n.init();
}
